  ('judicial-d3df8a4a-moex-00105', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '關於審計權之行使，下列敘述何者錯誤？', '["監察院設審計長，由總統提名，經立法院同意任命之", "審計長應於行政院提出決算後3個月內，依法完成其審核", "審計長完成決算審核後，應提出審核報告於立法院", "地方之審計權屬於地方立法並執行之事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00106', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '有關公務員懲戒，下列敘述何者正確？', '["法官之懲戒，亦包括大法官", "公務員懲戒法之適用對象，包括文職及武職之公務員、公立學校教師", "公務員懲戒案件之審理，為一級一審制", "司法院大法官之懲戒，得經司法院大法官現有總額3分之2以上之出席及出席人數3分之2以上之決 議，由司法院移送懲戒法院審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00107', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '司法院釋字第472號解釋宣示，針對無力繳納全民健康保險費者，國家應給予適當救助，不得逕行拒絕給 付，此為何種基本權？', '["生存權", "財產權", "人身自由", "一般行為自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
