  ('judicial-d3df8a4a-moex-00109', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '下列關於臺灣民商法發展之敘述，何者錯誤？', '["日治時期臺灣人的親屬繼承事項之實體法，原則上乃依照日本民法典", "戰前的日本民法典與戰後施行在臺灣的中華民國民法典，均以歐陸法為範本。是以戰前與戰後的臺灣民 事法之實質內容有許多延續之處", "1985年民法親屬繼承編首度修正，參考歐陸立法例朝向更平等的夫妻財產制", "戰後民商法的特色之一，為對於英美法，特別是美國法的繼受"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00110', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '有關地方政府得透過自治規章訂定行政罰則之規定，下列敘述何者錯誤？', '["直轄市法規、縣（市）規章就違反地方自治事項之行政業務者，得規定處以罰鍰或其他種類之行政罰", "直轄市政府、縣（市）政府得透過自治規則訂定罰鍰或其他種類之行政罰，惟需函送各該地方立法機關查照", "自治條例經各該地方立法機關決議後，如規定有罰則時，應分別報經行政院、中央各該主管機關核定後發布", "地方政府為罰鍰之規定，最高以新臺幣10萬元為限；逾期不繳納者，得依相關法律移送強制執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL)
